const text = items[0].json?.ParsedResults?.[0]?.ParsedText || '';
const cleaned = text
  .split('\n')
  .map(l => l.trim())
  .filter(l => l.length > 1)
  .join('\n');

return [
  {
    json: {
      ...items[0].json,
      extracted_image_text: cleaned
    }
  }
];

const item = $input.first().json;
const userMessage = String(item.user_message || '').trim();
const ocrText = String(item.extracted_image_text || '').trim();

const sourceText = [userMessage, ocrText]
  .filter(Boolean)
  .join(' ')
  .replace(/\u200B/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

function parseNumber(str) {
  if (!str) return null;
  let s = String(str).trim().replace(/\s/g, '');
  if (/^\d{1,3}(?:,\d{3})+$/.test(s)) {
    const num = Number(s.replace(/,/g, ''));
    return Number.isFinite(num) ? num : null;
  }
  const num = Number(
    s
      .replace(/,/g, '.')
      .replace(/[^0-9.]/g, '')
  );
  return Number.isFinite(num) ? num : null;
}

function normalizeCurrency(raw) {
  if (!raw) return null;
  const v = String(raw).toUpperCase().trim().split('/')[0];

  if (v === 'CN' || v === 'RMB' || v === 'ЮАНЬ' || v === 'ЮАНИ' || v.includes('ЮАН')) return 'CNY';
  if (v === '$' || v === 'ДОЛЛАР' || v === 'ДОЛЛ' || v.includes('ДОЛЛ')) return 'USD';
  if (v === '€' || v === 'ЕВРО' || v.includes('ЕВРО')) return 'EUR';
  if (v === '₽' || v === 'РУБ' || v.includes('РУБ')) return 'RUB';
  if (v === '¥') return 'CNY';

  if (['CNY', 'USD', 'EUR', 'RUB'].includes(v)) return v;
  return null;
}

function parseEuropeanQtyToken(tok) {
  const s = String(tok).trim();
  if (/^\d{1,3}(?:\.\d{3})+$/.test(s)) return parseNumber(s.replace(/\./g, ''));
  return parseNumber(s);
}

function parseEuropeanPriceToken(tok) {
  return parseNumber(String(tok).replace(',', '.'));
}

function tryParseProformaInvoice(text) {
  if (!/PROFORMA|P\.INVOICE|QTY\s*\/\s*PCS|ITEM\s*\/\s*PRODUCT|CRATE\s+KSK-/i.test(text)) return null;

  const rows = [];
  const rowRe = /(\d{1,3}(?:\.\d{3})+|\d{2,5})\s+(\d+[.,]\d+)\s*\$/gi;
  let rm;
  while ((rm = rowRe.exec(text)) !== null) {
    const qty = parseEuropeanQtyToken(rm[1]);
    const price = parseEuropeanPriceToken(rm[2]);
    if (qty && qty >= 1 && qty < 500000 && price && price > 0 && price < 1e6) {
      rows.push({ qty, price });
    }
  }
  if (!rows.length) return null;

  const quantity = rows.reduce((s, r) => s + r.qty, 0);
  const prices = [...new Set(rows.map((r) => r.price))];
  const unit_price = prices.length === 1 ? prices[0] : rows[0].price;

  const crates = [...text.matchAll(/CRATE\s+KSK-\d{3,4}\s+(?:BLUE|RED|GREEN)?/gi)].map((m) => m[0].trim());
  let product_name = null;
  if (crates.length === 1) {
    product_name = crates[0];
  } else if (crates.length > 1) {
    const base = crates[0].replace(/\s+(BLUE|RED|GREEN)$/i, '').trim();
    const colors = crates.map((c) => (c.match(/(BLUE|RED|GREEN)/i) || [])[0]).filter(Boolean);
    product_name = colors.length ? `${base} (${[...new Set(colors)].join(', ')})` : base;
  } else {
    product_name = 'Партия по инвойсу';
  }

  const currency = /\$|USD/i.test(text) ? 'USD' : null;
  return { product_name, quantity, unit_price, currency, parsed_from_invoice: true };
}

let quantity = null;
let unitPrice = null;
let currency = null;
let productName = null;
let exchangeRate = null;

let quantityMatch = null;
let priceMatch = null;
let ocrQtyMatch = null;
let priceAreaMatch = null;

const invoiceData = tryParseProformaInvoice(sourceText);
if (invoiceData) {
  quantity = invoiceData.quantity;
  unitPrice = invoiceData.unit_price;
  productName = invoiceData.product_name;
  currency = invoiceData.currency ? normalizeCurrency(invoiceData.currency) : normalizeCurrency('$');
}

if (!invoiceData) {
const QTY_UNIT_RX = '(?:pieces|pcs|шт|паллет(?:а|ы|ов)?|короб(?:а|ов)?|упак(?:овок)?)';
const CURR_WORD_RX = '(?:cny|rmb|usd|eur|rub|cn|евро|руб(?:лей|ля)?|доллар(?:ов|а|ы)?|долл\.?|юан(?:ей|я)?|юань)';
const CURR_SYM_RX = '(?:\\$|€|₽|¥)';
const CURRENCY_RX = `(?:${CURR_WORD_RX}|${CURR_SYM_RX})(?:\\/\\w+)?`;

// «15 паллет, 1000 долларов»
const qtyPricePairMatch = sourceText.match(
  new RegExp(`(?:^|[\\s,])(\\d+(?:[.,]\\d+)?)\\s*${QTY_UNIT_RX}\\s*[,;]\\s*(\\d+(?:[.,]\\d+)?)\\s*(${CURRENCY_RX})`, 'i')
);
if (qtyPricePairMatch) {
  quantity = parseNumber(qtyPricePairMatch[1]);
  unitPrice = parseNumber(qtyPricePairMatch[2]);
  currency = normalizeCurrency(qtyPricePairMatch[3]);
  quantityMatch = qtyPricePairMatch;
  priceMatch = qtyPricePairMatch;
}

// =========================
// 1) Количество
// =========================

// OCR-паттерн: "Количество 1 200"
if (!quantity) {
  ocrQtyMatch = sourceText.match(/Количество\s+(\d{1,3}(?:\s\d{3})*)\b/i);
  if (ocrQtyMatch) {
    const v = parseNumber(ocrQtyMatch[1]);
    if (Number.isFinite(v)) quantity = v;
  }
}

// Обычный паттерн: "11 660 шт", "15 паллет"
if (!quantity) {
  quantityMatch = sourceText.match(
    new RegExp(`(?:^|[\\s,-])(\\d{1,3}(?:,\\d{3})+|\\d{1,3}(?:\\s\\d{3})+|\\d+)\\s*${QTY_UNIT_RX}\\b`, 'i')
  );

  if (quantityMatch) {
    quantity = parseNumber(quantityMatch[1]);
  }
}

// =========================
// 2) Цена и валюта
// =========================

// OCR-паттерн: после слова "Цена" первая цена с валютой
if (!unitPrice) {
  priceAreaMatch = sourceText.match(
    new RegExp(`Цена[^0-9]{0,50}([\\d.,]+\\s*${CURRENCY_RX})`, 'i')
  );

  if (priceAreaMatch) {
    const raw = priceAreaMatch[1];
    const numMatch = raw.match(/[\d.,]+/);
    const currMatch = raw.match(new RegExp(`(${CURRENCY_RX})`, 'i'));

    if (numMatch) {
      const v = parseNumber(numMatch[0]);
      if (Number.isFinite(v)) unitPrice = v;
    }

    if (currMatch) {
      currency = normalizeCurrency(currMatch[1]);
    }
  }
}

// Обычный паттерн цены: "1000 долларов" (склонения валют без \\b)
if (!unitPrice) {
  priceMatch = sourceText.match(
    new RegExp(`(\\d+(?:[.,]\\d+)?)\\s*(${CURRENCY_RX})`, 'i')
  );

  if (priceMatch) {
    unitPrice = parseNumber(priceMatch[1]);
    currency = normalizeCurrency(priceMatch[2]);
  }
}

// Фоллбек валюты
if (!currency) {
  if (/RMB|CNY|\bCN\b|ЮАНЬ|ЮАНИ|ЮАН/i.test(sourceText)) currency = 'CNY';
  else if (/USD|\$|ДОЛЛАР|ДОЛЛ/i.test(sourceText)) currency = 'USD';
  else if (/EUR|€|ЕВРО/i.test(sourceText)) currency = 'EUR';
  else if (/RUB|₽|РУБ/i.test(sourceText)) currency = 'RUB';
}

// Фоллбек количества: не путать с ценой
if (!quantity) {
  if (unitPrice != null) {
    const otherNums = [...sourceText.matchAll(/(?:^|[\s,])(\d+(?:[.,]\d+)?)/g)]
      .map((m) => parseNumber(m[1]))
      .filter((n) => Number.isFinite(n) && n !== unitPrice);
    if (otherNums.length > 0) quantity = otherNums[0];
  } else {
    const allNums = [...sourceText.matchAll(/\d{1,3}(?:\s\d{3})+|\d{4,}/g)]
      .map((m) => m[0])
      .map((v) => ({ raw: v, num: parseNumber(v) }))
      .filter((v) => Number.isFinite(v.num));

    if (allNums.length > 0) quantity = allNums[0].num;
  }
}
}

if (!productName) {
// =========================
// 3) product_name (черновой)
// =========================

let prodText = sourceText;

// Убираем количество из OCR-блока
if (ocrQtyMatch) {
  prodText = prodText.replace(ocrQtyMatch[0], ' ');
}

// Убираем количество из обычного паттерна
if (quantityMatch) {
  prodText = prodText.replace(quantityMatch[0], ' ');
}

// Если количество нашли только фоллбеком — пробуем убрать его как число
if (!quantityMatch && !ocrQtyMatch && quantity) {
  const quantityVariants = [
    String(quantity),
    String(quantity).replace(/\B(?=(\d{3})+(?!\d))/g, ' '),
  ];

  for (const q of quantityVariants) {
    if (q) prodText = prodText.replace(q, ' ');
  }
}

// Убираем OCR-блок цены
if (priceAreaMatch) {
  prodText = prodText.replace(priceAreaMatch[0], ' ');
}

// Убираем обычный паттерн цены
if (priceMatch) {
  prodText = prodText.replace(priceMatch[0], ' ');
}

// Убираем валютные слова
prodText = prodText.replace(/\b(cny|rmb|usd|eur|rub|cn|евро|руб(?:лей|ля)?|доллар(?:ов|а|ы)?|долл\.?|юан(?:ей|я)?|юань)(?:\/\w+)?\b/gi, ' ');
prodText = prodText.replace(/\b(fob|sheet|sheets|pieces|pcs|паллет(?:а|ы|ов)?|короб(?:а|ов)?)\b/gi, ' ');
prodText = prodText.replace(/[€₽¥$]/g, ' ');

// Убираем sheet / sheets
prodText = prodText.replace(/\bsheets?\b/gi, ' ');

// Нормализация
prodText = prodText
  .replace(/[|;]+/g, ' ')
  .replace(/\s*,\s*/g, ' ')
  .replace(/\s*\/\s*/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

// =========================
// 3.1) product_name: обрезаем справа по маркерам
// =========================

const cutMarkers = [
  'Наружные размеры',
  'Внутренние размеры',
  'Полезная внутренняя высота',
  'Конструкция боковой части',
  'Конструкция основания',
  'Ручки торцевая сторона',
  'Ручки продольная сторона',
  'Объем',
  'Объём',
  'Вес',
  'Материал',
  'Производственная информация',
  'Цвет:',
  'Ожидаемая готовность',
  'изображения похожи',
  'Количество',
  'Цена за',
];

let baseName = prodText;
for (const marker of cutMarkers) {
  const idx = baseName.toLowerCase().indexOf(marker.toLowerCase());
  if (idx > 0) {
    baseName = baseName.slice(0, idx).trim();
    break;
  }
}

// =========================
// 3.2) product_name: обрезаем слева до "товарного" слова
// =========================

const startMarkers = [
  'Евроконтейнеры',
  'Контейнер',
  'Евро контейнер',
  'Короб',
  'Box',
];

let finalName = baseName;
for (const marker of startMarkers) {
  const idx = finalName.toLowerCase().indexOf(marker.toLowerCase());
  if (idx >= 0) {
    finalName = finalName.slice(idx).trim();
    break;
  }
}

// Если после обрезки пусто — откатываемся к baseName / prodText
if (!finalName) finalName = baseName || prodText;

// Финальная чистка пробелов
productName = finalName.replace(/\s+/g, ' ').trim() || null;
}

if (!productName && quantity && unitPrice && currency) {
  productName = 'Товар (уточнить)';
}

// =========================
// 4) Курсы
// =========================

const rates = {
  CNY: item.cny_rate,
  USD: item.usd_rate,
  EUR: item.eur_rate,
  RUB: 1,
};

exchangeRate = currency ? (rates[currency] || null) : null;

// =========================
// 5) Проверка обязательных полей
// =========================

const missing = [];
if (!productName) missing.push('product_name');
if (!quantity) missing.push('quantity');
if (!unitPrice) missing.push('unit_price');
if (!currency) missing.push('currency');

return [
  {
    json: {
      ...item,
      source_text: sourceText,
      parsed_product_name: productName,
      parsed_quantity: quantity,
      parsed_unit_price: unitPrice,
      parsed_currency: currency,
      parsed_exchange_rate: exchangeRate,
      parsed_calc_date: item.rate_date,
      missing_fields: missing,
      parse_ready: missing.length === 0,
    },
  },
];

messageValues.message:
Извлеки из текста данные о товаре. Верни ТОЛЬКО JSON без markdown:
{"product_name": "строка или null", "quantity": число или null, "unit_price": число или null, "currency": "CNY/USD/EUR/RUB или null"}
Правила: RMB и ¥ → CNY, $ → USD, € → EUR, ₽ → RUB. Количество и цена — только числа.

