const llmRaw = $input.first().json.text || $input.first().json.output || '';
let llm = {};
try { llm = typeof llmRaw === 'string' ? JSON.parse(llmRaw) : llmRaw; } catch(e) {}

return [{
json: {
...original,
parsed_product_name: original.parsed_product_name || llm.product_name || null,
parsed_quantity: original.parsed_quantity || llm.quantity || null,
parsed_unit_price: original.parsed_unit_price || llm.unit_price || null,
parsed_currency: original.parsed_currency || llm.currency || null,
parse_ready: !!(
(original.parsed_product_name || llm.product_name) &&
(original.parsed_quantity || llm.quantity) &&
(original.parsed_unit_price || llm.unit_price) &&
(original.parsed_currency || llm.currency)
),
llm_used: true
}
}];

const item = $input.first().json;

const product_name = item.parsed_product_name || null;
const quantity = item.parsed_quantity || null;
const unit_price = item.parsed_unit_price || null;
const currency = item.parsed_currency || null;
const exchange_rate = item.parsed_exchange_rate || null;
const calc_date = item.parsed_calc_date || item.rate_date || null;

const missing = [];
if (!product_name) missing.push('product_name');
if (!quantity) missing.push('quantity');
if (!unit_price) missing.push('unit_price');
if (!currency) missing.push('currency');

let status = 'need_more_data';
let message = 'Проверьте информацию о партии и уточните недостающие данные.';

if (missing.length === 0) {
  status = 'need_confirmation';
  message = null;
}

const output_parsed = {
  product_name,
  quantity,
  unit_price,
  currency,
  exchange_rate,
  calc_date,
  status,
  message,
};

return [{
  json: {
    ...item,
    product_name,
    quantity,
    unit_price,
    currency,
    exchange_rate,
    calc_date,
    status,
    message,
    output_parsed,
  }
}];

