const ctx = $('Set Request ID').first().json;
const targetRequestId = String(ctx.request_id || '').trim();
const chatId = Number(ctx.chat_id || 0);
const pollAttempt = Number(ctx.poll_attempt ?? 0);
const rows = $input.all();

function parseMoney(val) {
  if (val == null || val === '') return null;
  const n = Number(String(val).replace(/\s/g, '').replace(',', '.'));
  return Number.isFinite(n) ? n : null;
}

function isRowReady(row) {
  const j = row.json || {};
  const finalCost = parseMoney(j.final_cost_rub);
  if (finalCost != null && finalCost > 0) return true;
  const invoice = parseMoney(j.invoice_total_foreign);
  if (invoice != null && invoice > 0) return true;
  return false;
}

const matched = rows.filter((item) => {
  const rowRequestId = String(item.json.request_id || '').trim();
  return rowRequestId === targetRequestId;
});

const readyRow = matched.find(isRowReady);

if (readyRow) {
  return [{
    json: {
      ...readyRow.json,
      result_ready: true,
      chat_id: chatId || readyRow.json.chat_id,
    },
  }];
}

return [{
  json: {
    result_ready: false,
    request_id: targetRequestId,
    chat_id: chatId,
    poll_attempt: pollAttempt,
  },
}];

const item = $input.first().json;
return [{
  json: {
    request_id: item.request_id,
    chat_id: item.chat_id,
    poll_attempt: Number(item.poll_attempt ?? 0) + 1,
  },
}];

