const staticData = $getWorkflowStaticData('global');
const item = $input.first().json;
const chatId = String(item.chat_id || 0);
if (chatId !== '0') delete staticData[chatId];
return [{ json: { ...item, session_action: 'clear' } }];

const staticData = $getWorkflowStaticData('global');
const trigger = $('Telegram Trigger').first().json;
const msg = trigger.message || {};
const cq = trigger.callback_query || {};
const chatIdRaw = msg.chat?.id ?? cq.message?.chat?.id ?? msg.from?.id ?? cq.from?.id ?? 0;
const chatId = String(chatIdRaw);
const text = String(msg.text || msg.caption || '').trim();
const callback = String(cq.data || '').trim();

let sheetSaved = null;
try {
  const sheetRows = $('Read Session Sheet').all();
  for (const row of sheetRows) {
    const rowChatId = String(row.json?.chat_id ?? '').trim();
    if (!rowChatId || rowChatId !== chatId) continue;
    let draft = null;
    try {
      const parsed = JSON.parse(row.json.draft_json || '{}');
      if (parsed && typeof parsed === 'object' && Object.keys(parsed).length) draft = parsed;
    } catch (e) {}
    sheetSaved = {
      state: String(row.json.state || 'new'),
      draft,
      edit_field: row.json.edit_field ? String(row.json.edit_field) : null,
    };
    break;
  }
} catch (e) {}

let saved = staticData[chatId] || {};
const staticHasData =
  (saved.state && saved.state !== 'new') ||
  (saved.draft && typeof saved.draft === 'object' && Object.keys(saved.draft).length) ||
  !!saved.edit_field;
if (sheetSaved !== null && !staticHasData) {
  saved = {
    state: sheetSaved.state || 'new',
    draft: sheetSaved.draft,
    edit_field: sheetSaved.edit_field,
  };
} else if (sheetSaved !== null && staticHasData) {
  saved = {
    state: saved.state || sheetSaved.state || 'new',
    draft: saved.draft || sheetSaved.draft,
    edit_field: saved.edit_field || sheetSaved.edit_field,
  };
}

const editField = saved.edit_field || null;
const isResetCommand = /^(\/start|\/reset|сброс)$/i.test(text);
const isNewMessageAtConfirm =
  saved.state === 'waiting_confirmation' &&
  text &&
  !callback &&
  !editField;
const sessionNeedsClear = isResetCommand || isNewMessageAtConfirm;

if (chatId !== '0' && sessionNeedsClear) {
  delete staticData[chatId];
  saved = {};
}

const draft = saved.draft || null;
const savedState = saved.state || 'new';

return [{
  json: {
    ...trigger,
    chat_id: Number(chatIdRaw || 0),
    user_message: isResetCommand ? '' : text,
    callback_action: callback,
    saved_state: savedState,
    saved_draft: draft,
    output_parsed: draft,
    edit_field: saved.edit_field || null,
    reset_requested: isResetCommand,
    session_needs_clear: sessionNeedsClear,
    session_action: sessionNeedsClear ? 'clear' : undefined,
  },
}];

const staticData = $getWorkflowStaticData('global');
const chatId = String($json.chat_id || 0);
const draft = $json.saved_draft || {};
const action = String($json.callback_action || '');
const field = action.replace('edit_', '');
staticData[chatId] = { state: 'waiting_confirmation', draft: { ...draft }, edit_field: field };
return [{ json: { ...$json, edit_field: field } }];

const staticData = $getWorkflowStaticData('global');
const chatId = String($json.chat_id || 0);
const saved = staticData[chatId] || {};
const editField = $json.edit_field || saved.edit_field || null;
const text = String($json.user_message || '').trim();
const hasPhoto = !!($json.message?.photo || $json.message?.document);
if (!editField) { return [{ json: { ...$json, reset_to_new: true, correction_valid: false } }]; }
if (hasPhoto) { return [{ json: { ...$json, correction_valid: false, error_message: 'Для исправления отправьте только текстовое значение, без фото и документов.' } }]; }
const updates = {};
function parseNum(str) { const n = Number(String(str).replace(/\s/g,'').replace(',','.').replace(/[^0-9.]/g,'')); return Number.isFinite(n) && n>0 ? n : null; }
function normalizeCurrency(raw) { const v = String(raw).toUpperCase().trim(); if (['RMB','CNY'].includes(v) || v.includes('ЮАН')) return 'CNY'; if (['USD','$'].includes(v) || v.includes('ДОЛ')) return 'USD'; if (['EUR','€'].includes(v) || v.includes('ЕВРО')) return 'EUR'; if (['RUB','₽'].includes(v) || v.includes('РУБ')) return 'RUB'; return null; }
if (editField === 'quantity') { const v = parseNum(text); if (v) updates.quantity = v; }
if (editField === 'price') { const v = parseNum(text); if (v) updates.unit_price = v; }
if (editField === 'currency') { const c = normalizeCurrency(text); if (c) updates.currency = c; }
if (editField === 'product') { if (text) updates.product_name = text; }
return [{ json: { ...$json, updates, correction_valid: Object.keys(updates).length > 0 } }];

const staticData = $getWorkflowStaticData('global');
const item = $('If Edit Valid Simple').first().json;
const chatId = String(item.chat_id || 0);
const saved = staticData[chatId] || {};
const draft = item.saved_draft || saved.draft || {};
const updates = item.updates || {};
const corrected = { ...draft, ...updates, status: 'need_confirmation' };

if (updates.currency && corrected.currency) {
  try {
    const cbr = $('Курс ЦБ Edit').first().json;
    const raw = cbr.data ?? cbr.body ?? cbr;
    const d = typeof raw === 'string' ? JSON.parse(raw) : (raw.Valute ? raw : JSON.parse(JSON.stringify(raw)));
    const rates = {
      CNY: d.Valute?.CNY?.Value,
      USD: d.Valute?.USD?.Value,
      EUR: d.Valute?.EUR?.Value,
      RUB: 1,
    };
    const cur = corrected.currency;
    if (rates[cur] != null) corrected.exchange_rate = rates[cur];
    if (d.Date) corrected.calc_date = d.Date;
  } catch (e) {
    corrected.exchange_rate_refresh_error = String(e?.message || e);
  }
