return [{ json: { ...$json, saved_state: 'new', session_action: 'clear', chat_id: Number($json.chat_id || 0) } }];

const staticData = $getWorkflowStaticData('global');
const item = $input.first().json;
const chatId = String(item.chat_id || 0);
const prev = staticData[chatId] || {};
const draft = item.output_parsed || prev.draft || {};
if (chatId !== '0') { staticData[chatId] = { state: 'waiting_confirmation', draft }; }
return [{ json: { ...item, saved_draft: draft } }];

const item = $input.first().json;
const chatId = String(item.chat_id || 0);
if (chatId === '0') return [{ json: item }];

const action = item.session_action || (item.session_needs_clear ? 'clear' : 'upsert');
let state = 'new';
let draft = {};
let editField = '';

if (action === 'clear') {
  state = 'new';
} else {
  if (item.output_parsed) {
    state = 'waiting_confirmation';
    draft = item.output_parsed;
  } else if (item.saved_draft) {
    state = 'waiting_confirmation';
    draft = item.saved_draft;
  } else if (item.saved_state) {
    state = item.saved_state;
    draft = item.saved_draft || {};
  }
  editField = item.edit_field || '';
}

let sessionRestoreTarget = 'router';
if (item.edit_field) {
  sessionRestoreTarget = 'ask_edit';
} else if (item.output_parsed?.status === 'need_confirmation') {
  sessionRestoreTarget = 'route_by_status';
} else if (item.reset_requested || (item.session_action === 'clear' && item.saved_state === 'new')) {
  sessionRestoreTarget = 'reset_message';
}

return [{
  json: {
    ...item,
    session_chat_id: chatId,
    session_state: state,
    session_draft_json: JSON.stringify(draft && typeof draft === 'object' ? draft : {}),
    session_edit_field: String(editField || ''),
    session_updated_at: new Date().toISOString(),
    session_restore_target: sessionRestoreTarget,
  },
}];
